import json

# Get the repository list from query_db:10
storage_key = 'var_functions.query_db:10'
result = locals().get(storage_key, [])

# Extract repo names
repo_names = []
if result:
    if isinstance(result, list):
        for item in result:
            if isinstance(item, dict) and 'repo_name' in item:
                repo_names.append(item['repo_name'])

# Query commits for these repos using the DuckDB IN operator
# Format the repo names as a comma-separated string with quotes
if repo_names:
    repo_list_str = ', '.join([f"'{name}'" for name in repo_names[:50]])  # Limit to first 50 for now

    print('__RESULT__:')
    print(json.dumps({
        "repo_count": len(repo_names),
        "sample_repos": repo_names[:5],
        "repo_list_str_preview": repo_list_str[:100]
    }))
else:
    print('__RESULT__:')
    print(json.dumps({"error": "No repos found", "debug": str(result)[:100]}))

